mapper.insert:
INSERT INTO SCHEDULE
	( SCHEDULE_ID
	, PROGRAM_ID
	, EVENT_DATE
	, EVENT_TIME
	, TOTAL_SEATS
	, AVAIL_SEATS
	, SESSION_NO
	, ONLINE_CAPACITY
	, OFFLINE_CAPACITY
	, ONLINE_AVAIL
	, OFFLINE_AVAIL
	, STATUS
	, REG_DT )
VALUES
	( #{scheduleId}
	, #{programId}
	, #{eventDate, jdbcType=DATE}
	, #{eventTime}
	, #{totalSeats}
	, #{availSeats}
	, #{sessionNo}
	, #{onlineCapacity}
	, #{offlineCapacity}
	, #{onlineAvail}
	, #{offlineAvail}
	, #{status}
	, GETDATE() )

mapper.update:
UPDATE SCHEDULE
SET PROGRAM_ID       = #{programId}
  , EVENT_DATE       = #{eventDate, jdbcType=DATE}
  , EVENT_TIME       = #{eventTime}
  , TOTAL_SEATS      = #{totalSeats}
  , AVAIL_SEATS      = #{availSeats}
  , SESSION_NO       = #{sessionNo}
  , ONLINE_CAPACITY  = #{onlineCapacity}
  , OFFLINE_CAPACITY = #{offlineCapacity}
  , ONLINE_AVAIL     = #{onlineAvail}
  , OFFLINE_AVAIL    = #{offlineAvail}
  , STATUS           = #{status}
WHERE SCHEDULE_ID = #{scheduleId}

mapper.select:
SELECT COUNT(*) totcnt FROM SCHEDULE S LEFT JOIN PROGRAM P ON S.PROGRAM_ID = P.PROGRAM_ID WHERE 1=1
AND S.SCHEDULE_ID LIKE CONCAT('%', #{searchKeyword}, '%')
AND S.STATUS = #{searchKeyword}

mapper.update:
UPDATE SCHEDULE
SET ONLINE_AVAIL = ONLINE_AVAIL - #{onlineAvail},
    AVAIL_SEATS  = AVAIL_SEATS - #{onlineAvail}
WHERE SCHEDULE_ID = #{scheduleId}
  AND ONLINE_AVAIL >= #{onlineAvail}

mapper.delete:
DELETE FROM DATE_PRICE_OVERRIDE
WHERE PROGRAM_ID = #{programId} AND EVENT_DATE = #{eventDate}
  AND SESSION_NO = #{sessionNo} AND TYPE_ID = #{typeId}

mapper.select:
SELECT COUNT(*) FROM SCHEDULE
WHERE PROGRAM_ID = #{programId}
  AND CONVERT(VARCHAR(10), EVENT_DATE, 23) = #{eventDate}
  AND SESSION_NO = #{sessionNo}
